import React, { useState, useEffect } from "react";
import LoginForm from "./LoginForm"; // nhớ file này tồn tại

export default function App() {
  const [showLogin, setShowLogin] = useState(false);

  // Khi App load, tự động chuyển sau 2 giây
  useEffect(() => {
    const timer = setTimeout(() => {
      setShowLogin(true);
    }, 2000); // 2000ms = 2 giây

    return () => clearTimeout(timer); // cleanup nếu component unmount
  }, []);

  return (
    <div className="min-h-screen flex justify-center items-center bg-white">
      {showLogin ? (
        <LoginForm />
      ) : (
        <div className="flex flex-col items-center">
          <img src="/logo.png" alt="Logo" className="w-48 h-48 mb-6" />
          <span className="text-2xl font-semibold">Chào mừng!</span>
        </div>
      )}
    </div>
  );
}
